async (params, browser) => {
  // Open tweet composer
  await browser.open('https://x.com/compose/post')

  // Wait for compose box
  await browser.waitForSelector('[data-testid^=\'tweetTextarea\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Focus compose box
  await browser.click('[data-testid^=\'tweetTextarea\']')

  // Wait for focus
  await browser.wait(300)

  // Type tweet text
  const type_text = await browser.evaluate(`const txt = params.text; if (txt.length > 280) throw new Error('Tweet exceeds 280 characters (' + txt.length + ' chars). Please shorten it.'); const el = document.querySelector('[data-testid^="tweetTextarea"] [contenteditable="true"], [data-testid^="tweetTextarea"][contenteditable="true"], [data-testid^="tweetTextarea"]'); if (!el) throw new Error('Tweet textarea not found'); el.focus(); document.execCommand('insertText', false, txt); el.dispatchEvent(new Event('input', {bubbles: true})); return { typed: true, characters: txt.length }`)

  // Brief pause before posting
  await browser.wait(500)

  // Click Post button
  await browser.click('[data-testid^=\'tweetButton\'], [data-testid=\'tweetButton\']')

  // Wait for tweet to post
  await browser.wait(3000)

  // Confirm post
  const result = await browser.evaluate(`return { success: true, message: 'Tweet posted successfully' }`)

  return result
}
